//
//  StaticCommands.swift
//  hxguide
//
//  The static command list — every command that can be bound to a key, as
//  distinct from the typable `:` commands in Commands.swift.
//  Source: helix book/src/generated/static-cmd.md
//

import Foundation

extension Helix {

    /// A bindable Helix command: its name, what it does, and where it is bound
    /// by default. Unlike a keymap row this is keyed by *command*, so the same
    /// command appears once even when several keys reach it.
    struct StaticCommand: Identifiable, Hashable {
        /// The command name as written in `config.toml`, e.g. `move_char_left`.
        let name: String
        /// Human-readable explanation.
        let detail: String
        /// Default bindings, already formatted for display; empty when unbound.
        let bindings: String

        var id: String { name }
    }

    enum StaticCommands {
        static let all: [StaticCommand] = [
