        /// Projection into the shared row model. The command name is the key
        /// column here — this screen is browsed by command, not by keystroke.
        static var entries: [GuideEntry] {
            all.map {
                GuideEntry(id: $0.name,
                           key: $0.name,
                           detail: $0.bindings.isEmpty
                               ? $0.detail
                               : "\($0.detail) — \($0.bindings)")
            }
        }
